const vendedores = $input.all().map(item => item.json);

if (!vendedores.length) {
  return [{ json: { skip: true, reason: 'Sem dados na semana' } }];
}

// Calcula tendências
const relatorios = vendedores.map(v => {
  const delta = v.taxa_conversao - (v.taxa_conversao_semana_anterior || v.taxa_conversao);
  const tendencia = delta > 5 ? 'crescendo' : delta < -5 ? 'caindo' : 'estavel';

  return {
    ...v,
    tendencia,
    delta_conversao: parseFloat(delta.toFixed(2))
  };
});

// Time completo
const total_conversas  = relatorios.reduce((s, v) => s + v.total_conversas, 0);
const total_conversoes = relatorios.reduce((s, v) => s + v.conversoes, 0);
const taxa_time        = total_conversas > 0
  ? parseFloat((100 * total_conversoes / total_conversas).toFixed(2))
  : 0;
const score_time       = parseFloat(
  (relatorios.reduce((s, v) => s + parseFloat(v.score_medio || 0), 0) / relatorios.length).toFixed(2)
);

const periodo_inicio = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
const periodo_fim    = new Date().toISOString().split('T')[0];

const prompt = `Você é um gerente comercial analisando a performance semanal do time de vendas.

Dados do time — semana de ${periodo_inicio} a ${periodo_fim}:
- Total de conversas: ${total_conversas}
- Taxa de conversão do time: ${taxa_time}%
- Score médio de qualidade: ${score_time}/10

Por vendedor:
${relatorios.map(v =>
  `• ${v.vendedor_nome}: ${v.total_conversas} conversas | ${v.taxa_conversao}% conversão | score ${v.score_medio} | tendência: ${v.tendencia} (${v.delta_conversao > 0 ? '+' : ''}${v.delta_conversao}pp)`
).join('\n')}

Perfis e gaps conhecidos:
${relatorios.filter(v => v.perfil_gaps).map(v =>
  `• ${v.vendedor_nome} — gaps: ${JSON.stringify(v.perfil_gaps).substring(0,150)}`
).join('\n')}

Retorne APENAS um JSON válido (sem markdown):
{
  "score_time": ${score_time},
  "taxa_conversao_time": ${taxa_time},
  "tendencia_time": "crescendo|estavel|caindo",
  "top_insights": [
    "insight acionável 1 (específico, baseado nos dados)",
    "insight acionável 2",
    "insight acionável 3"
  ],
  "alertas": [
    {"vendedor": "nome", "problema": "descrição", "urgencia": "alta|media"}
  ],
  "recomendacoes_time": [
    {"acao": "ação específica", "impacto_esperado": "resultado esperado", "prioridade": "1|2|3"}
  ],
  "destaque_positivo": "nome do vendedor com melhor performance e por quê"
}`;

return [{
  json: {
    relatorios,
    total_conversas,
    total_conversoes,
    taxa_time,
    score_time,
    periodo_inicio,
    periodo_fim,
    prompt
  }
}];

