const ctx = $('calcular-metricas').first().json;
const claudeResponse = $input.first().json;

let insights;
try {
  const content = claudeResponse.content?.[0]?.text || '{}';
  insights = JSON.parse(content);
} catch(e) {
  insights = { top_insights: [], alertas: [], recomendacoes_time: [] };
}

// Salva relatório por vendedor + relatório do time
const relatorios_para_salvar = [
  // Relatório do time (vendedor_id = null)
  {
    vendedor_id:    null,
    periodo_inicio: ctx.periodo_inicio,
    periodo_fim:    ctx.periodo_fim,
    tipo_relatorio: 'weekly',
    score_geral:    ctx.score_time,
    taxa_conversao: ctx.taxa_time,
    tendencia:      insights.tendencia_time || 'estavel',
    top_insights:   insights.top_insights || [],
    recomendacoes:  insights.recomendacoes_time || [],
    alertas:        insights.alertas || [],
    metricas_detalhe: {
      total_conversas:  ctx.total_conversas,
      total_conversoes: ctx.total_conversoes,
      destaque_positivo: insights.destaque_positivo,
      por_vendedor: ctx.relatorios.map(v => ({
        vendedor_id:   v.vendedor_id,
        nome:          v.vendedor_nome,
        conversas:     v.total_conversas,
        conversoes:    v.conversoes,
        taxa:          v.taxa_conversao,
        score:         v.score_medio,
        tendencia:     v.tendencia,
        delta:         v.delta_conversao
      }))
    }
  },
  // Relatório individual por vendedor
  ...ctx.relatorios.map(v => ({
    vendedor_id:    v.vendedor_id,
    periodo_inicio: ctx.periodo_inicio,
    periodo_fim:    ctx.periodo_fim,
    tipo_relatorio: 'weekly',
    score_geral:    v.score_medio,
    taxa_conversao: v.taxa_conversao,
    tendencia:      v.tendencia,
    top_insights:   [],
    recomendacoes:  v.perfil_recomendacoes || [],
    alertas:        (insights.alertas || []).filter(a => a.vendedor === v.vendedor_nome),
    metricas_detalhe: {
      conversas:  v.total_conversas,
      conversoes: v.conversoes,
      perdas:     v.perdas,
      pendentes:  v.pendentes,
      top_objecoes: v.top_objecoes || []
    }
  }))
];

return relatorios_para_salvar.map(r => ({ json: r }));
